<?phpnamespace PC_CPQ\Helpers;if ( ! defined( 'ABSPATH' ) )	exit;class Quotes{	static public $header;	static public $footer;	static public $terms;	static public function set_defaults()	{		if ( ! function_exists( 'get_field' ) ) {			return null;		}				self::$header = get_field( 'quote_header', 'option' );		self::$footer = get_field( 'quote_footer', 'option' );		self::$terms = get_field( 'quote_terms', 'option' );	}}Quotes::set_defaults();